-- USJ graduate data seed migration.
-- Idempotent import for the canonical USJ graduate dataset.
--
-- Schema adjustment: allow hub/catalog URLs to be reused across multiple graduate programs.
ALTER TABLE graduate_program DROP CONSTRAINT IF EXISTS uq_graduate_program_university_url;

DO $$
DECLARE
    v_university_id BIGINT;
BEGIN

    INSERT INTO university (name, name_ar, acronym, country, city, latitude, longitude, campus_name, campus_type)
    SELECT 'Université Saint-Joseph de Beyrouth', NULL, 'USJ', 'Lebanon', 'Beirut', NULL, NULL, NULL, NULL
    WHERE NOT EXISTS (
        SELECT 1 FROM university WHERE name = 'Université Saint-Joseph de Beyrouth'
    );

    SELECT id INTO v_university_id
    FROM university
    WHERE name = 'Université Saint-Joseph de Beyrouth'
    ORDER BY id
    LIMIT 1;

    INSERT INTO degree_type (code, name)
    VALUES
        ('MASTER', 'Master'),
        ('PHD', 'Doctor of Philosophy')
    ON CONFLICT (code) DO UPDATE SET
        name = EXCLUDED.name,
        updated_at = NOW();

    INSERT INTO language (name, code, native_name)
    VALUES
        ('Arabic', 'ar', 'العربية'),
        ('English', 'en', 'English'),
        ('French', 'fr', 'Français'),
        ('Multilingual', 'multi', 'Multilingual')
    ON CONFLICT (code) DO UPDATE SET
        name = EXCLUDED.name,
        native_name = EXCLUDED.native_name;

    CREATE TEMP TABLE usj_source_seed (
        source_id TEXT PRIMARY KEY,
        page_title TEXT NOT NULL,
        url TEXT NOT NULL,
        date_accessed DATE,
        source_type TEXT NOT NULL
    ) ON COMMIT DROP;

    INSERT INTO usj_source_seed (source_id, page_title, url, date_accessed, source_type)
    SELECT source_id, page_title, url, date_accessed, source_type
    FROM jsonb_to_recordset($USJ$[{"source_id": "usj_home_en", "page_title": "Université Saint-Joseph de Beyrouth", "url": "https://usj.edu.lb/en", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_home_fr", "page_title": "Université Saint-Joseph de Beyrouth", "url": "https://usj.edu.lb/fr", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_grad_catalog_fr", "page_title": "homepage - e-doors master | Université Saint-Joseph de Beyrouth", "url": "https://usj.edu.lb/fr/e-doors/masters", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_admission_master_fr", "page_title": "Admission: Master’s Degree", "url": "https://usj.edu.lb/fr/admission/admis-master", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_admission_doctorat_fr", "page_title": "Admission en doctorat", "url": "https://usj.edu.lb/fr/admission/admis-doctorat", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_equivalences", "page_title": "Équivalences", "url": "https://usj.edu.lb/admission/equivalences.php", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_admission_equivalences_fr", "page_title": "Équivalences et validations", "url": "https://usj.edu.lb/fr/admission/equivalences", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_admission_documents_fr", "page_title": "Documents requis - admission", "url": "https://usj.edu.lb/fr/admission/documents", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_aide", "page_title": "Aides financières", "url": "https://usj.edu.lb/aide/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_reglement_etudes_pdf", "page_title": "Règlement intérieur des études", "url": "https://www.usj.edu.lb/pdf/reglementdesetudes.pdf", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_accreditation_inst", "page_title": "Accréditation institutionnelle", "url": "https://usj.edu.lb/qualite/acc-inst.php", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_social_services_fr", "page_title": "Services sociaux", "url": "https://usj.edu.lb/fr/ss", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_fgm", "page_title": "Faculté de gestion et de management", "url": "https://usj.edu.lb/fgm/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_fgm_mba_dossier_pdf", "page_title": "Dossier d'inscription MBA promo 24", "url": "https://usjweb.usj.edu.lb/fgm/pdf/front/dossier-inscription-MBA-Promo24.pdf", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_fgm_presentation_master_pdf", "page_title": "Présentation Master", "url": "https://usjweb.usj.edu.lb/fgm/pdf/front/Presentation-Master.pdf", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_fgm_masters_presentation_pdf", "page_title": "Master's Presentation", "url": "https://usjweb.usj.edu.lb/fgm/pdf/front/Masters-Presentation.pdf", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_isp", "page_title": "Institut de sciences politiques", "url": "https://usj.edu.lb/isp/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_fdsp", "page_title": "Faculté de droit et des sciences politiques", "url": "https://usj.edu.lb/fdsp/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_fdlt", "page_title": "Faculté de langues et de traduction", "url": "https://usj.edu.lb/fdlt/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_fia", "page_title": "Faculté d'ingénierie et d'architecture", "url": "https://usj.edu.lb/fia/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_fmd", "page_title": "Faculté de médecine", "url": "https://usj.edu.lb/fmd/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_fsi", "page_title": "Faculté de sciences infirmières", "url": "https://usj.edu.lb/fsi/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_fp", "page_title": "Faculté de pharmacie", "url": "https://usj.edu.lb/fp/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_fs", "page_title": "Faculté des sciences", "url": "https://usj.edu.lb/fs/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_fs_formations_fr", "page_title": "Formations - fs", "url": "https://usj.edu.lb/fr/fs/formations", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_fs_biomarketing_pdf", "page_title": "Master in Biomarketing", "url": "https://www.usj.edu.lb/catalogues/25-26/fr/FS/FS-13-Master%20in%20Biomarketing.pdf", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_fs_data_science_pdf", "page_title": "Master in Data Science", "url": "https://www.usj.edu.lb/catalogues/25-26/fr/FS/FS-14-Master%20in%20Data%20Science.pdf", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_fs_environment_pdf", "page_title": "Master en sciences et gestion de l'environnement", "url": "https://www.usj.edu.lb/catalogues/25-26/fr/FS/FS-11-Master%20en%20sciences%20et%20gestion%20de%20l%20environnement.pdf", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_flsh", "page_title": "Faculté des lettres et des sciences humaines", "url": "https://usj.edu.lb/flsh/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_elfs", "page_title": "École de travail social", "url": "https://usj.edu.lb/elfs/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_school_iesav", "page_title": "Institut d'études scéniques, audiovisuelles et cinématographiques", "url": "https://usj.edu.lb/iesav/", "date_accessed": "2026-06-27", "source_type": "WEB"}, {"source_id": "usj_tuition_2024_2025", "page_title": "05.2-Costofcredit2ndcycle.pdf", "url": "https://www.usj.edu.lb/pdf/05.2-Costofcredit2ndcycle.pdf", "date_accessed": "2026-06-27", "source_type": "PDF"}]$USJ$::jsonb) AS src(
        source_id TEXT,
        page_title TEXT,
        url TEXT,
        date_accessed DATE,
        source_type TEXT
    );

    INSERT INTO source (university_id, title, url, source_type, accessed_at)
    SELECT v_university_id, page_title, url, source_type, date_accessed
    FROM usj_source_seed
    ON CONFLICT (university_id, url) DO UPDATE SET
        title = EXCLUDED.title,
        source_type = EXCLUDED.source_type,
        accessed_at = EXCLUDED.accessed_at,
        updated_at = NOW();

    INSERT INTO university_faculty (university_id, name, short_name, faculty_type, official_url, notes)
    SELECT v_university_id, name, short_name, faculty_type, official_url, notes
    FROM jsonb_to_recordset($USJ$[{"name": "Faculté de droit et des sciences politiques", "short_name": null, "faculty_type": "FACULTY", "official_url": "https://usj.edu.lb/fdsp/", "notes": "Imported from USJ graduate program data."}, {"name": "Faculté de gestion et de management", "short_name": null, "faculty_type": "FACULTY", "official_url": "https://usj.edu.lb/fgm/", "notes": "Imported from USJ graduate program data."}, {"name": "Faculté de langues et de traduction", "short_name": null, "faculty_type": "FACULTY", "official_url": "https://usj.edu.lb/fdlt/", "notes": "Imported from USJ graduate program data."}, {"name": "Faculté de médecine", "short_name": null, "faculty_type": "FACULTY", "official_url": "https://usj.edu.lb/fmd/", "notes": "Imported from USJ graduate program data."}, {"name": "Faculté de pharmacie", "short_name": null, "faculty_type": "FACULTY", "official_url": "https://usj.edu.lb/fp/", "notes": "Imported from USJ graduate program data."}, {"name": "Faculté des lettres et des sciences humaines Ramez G. Chagoury", "short_name": null, "faculty_type": "FACULTY", "official_url": "https://usj.edu.lb/flsh/", "notes": "Imported from USJ graduate program data."}, {"name": "Faculté des sciences", "short_name": null, "faculty_type": "FACULTY", "official_url": "https://usj.edu.lb/fs/", "notes": "Imported from USJ graduate program data."}, {"name": "Faculté des sciences infirmières", "short_name": null, "faculty_type": "FACULTY", "official_url": "https://usj.edu.lb/fsi/", "notes": "Imported from USJ graduate program data."}, {"name": "Institut d'études scéniques, audiovisuelles et cinématographiques", "short_name": null, "faculty_type": "INSTITUTE", "official_url": "https://usj.edu.lb/iesav/", "notes": "Imported from USJ graduate program data."}, {"name": "Institut supérieur de santé publique", "short_name": null, "faculty_type": "INSTITUTE", "official_url": "https://usj.edu.lb/fmd/", "notes": "Imported from USJ graduate program data."}]$USJ$::jsonb) AS fac(
        name TEXT,
        short_name TEXT,
        faculty_type TEXT,
        official_url TEXT,
        notes TEXT
    )
    ON CONFLICT (university_id, name) DO UPDATE SET
        short_name = EXCLUDED.short_name,
        faculty_type = EXCLUDED.faculty_type,
        official_url = EXCLUDED.official_url,
        notes = EXCLUDED.notes,
        updated_at = NOW();

    INSERT INTO university_department (university_id, faculty_id, name, short_name, official_url, notes)
    SELECT v_university_id, fac.id, dep.name, dep.short_name, dep.official_url, dep.notes
    FROM jsonb_to_recordset($USJ$[{"faculty_name": "Faculté de droit et des sciences politiques", "name": "Faculté de droit", "short_name": null, "official_url": null, "notes": null}, {"faculty_name": "Faculté de droit et des sciences politiques", "name": "Institut des sciences politiques", "short_name": null, "official_url": null, "notes": null}, {"faculty_name": "Faculté de gestion et de management", "name": "Faculté de gestion et de management", "short_name": null, "official_url": null, "notes": null}, {"faculty_name": "Faculté des sciences", "name": "Département de chimie", "short_name": null, "official_url": null, "notes": null}, {"faculty_name": "Faculté des sciences", "name": "Département de mathématiques", "short_name": null, "official_url": null, "notes": null}, {"faculty_name": "Faculté des sciences", "name": "Département de physique", "short_name": null, "official_url": null, "notes": null}, {"faculty_name": "Faculté des sciences", "name": "Département de sciences de la vie et de la terre", "short_name": null, "official_url": null, "notes": null}]$USJ$::jsonb) AS dep(
        faculty_name TEXT,
        name TEXT,
        short_name TEXT,
        official_url TEXT,
        notes TEXT
    )
    JOIN university_faculty fac
      ON fac.university_id = v_university_id
     AND fac.name = dep.faculty_name
    ON CONFLICT (university_id, faculty_id, name) DO UPDATE SET
        short_name = EXCLUDED.short_name,
        official_url = EXCLUDED.official_url,
        notes = EXCLUDED.notes,
        updated_at = NOW();

    CREATE TEMP TABLE usj_program_seed (
        id TEXT PRIMARY KEY,
        faculty TEXT NOT NULL,
        department TEXT,
        major_category TEXT,
        major TEXT,
        degree_type TEXT NOT NULL,
        official_degree_name TEXT,
        thesis_or_non_thesis TEXT,
        credits INTEGER,
        duration_value NUMERIC(10, 2),
        duration_unit TEXT,
        duration_raw_text TEXT,
        language TEXT,
        delivery_mode TEXT,
        program_description TEXT,
        admission_requirements TEXT,
        gre_requirement TEXT,
        gmat_requirement TEXT,
        english_requirement TEXT,
        interview_requirement TEXT,
        experience_requirement TEXT,
        accreditation TEXT,
        official_program_url TEXT,
        source_ids JSONB,
        notes TEXT
    ) ON COMMIT DROP;

    INSERT INTO usj_program_seed (
        id, faculty, department, major_category, major, degree_type, official_degree_name, thesis_or_non_thesis, credits,
        duration_value, duration_unit, duration_raw_text, language, delivery_mode, program_description, admission_requirements,
        gre_requirement, gmat_requirement, english_requirement, interview_requirement, experience_requirement, accreditation,
        official_program_url, source_ids, notes
    )
    SELECT
        id, faculty, department, major_category, major, degree_type, official_degree_name, thesis_or_non_thesis, credits,
        duration_value, duration_unit, duration_raw_text, language, delivery_mode, program_description, admission_requirements,
        gre_requirement, gmat_requirement, english_requirement, interview_requirement, experience_requirement, accreditation,
        official_program_url, source_ids, notes
    FROM jsonb_to_recordset($USJ$[{"id": "usj-flsh-master-history-international-relations", "faculty": "Faculté des lettres et des sciences humaines Ramez G. Chagoury", "department": null, "major_category": "Arts, lettres et sciences humaines", "major": "Histoire - Relations internationales", "degree_type": "MASTER", "official_degree_name": "Master en Histoire - Relations internationales", "thesis_or_non_thesis": null, "credits": null, "duration_value": null, "duration_unit": null, "duration_raw_text": null, "language": null, "delivery_mode": null, "program_description": null, "admission_requirements": null, "gre_requirement": null, "gmat_requirement": null, "english_requirement": null, "interview_requirement": null, "experience_requirement": null, "accreditation": null, "official_program_url": "https://usj.edu.lb/fr/e-doors/masters", "source_ids": ["usj_grad_catalog_fr", "usj_school_flsh"], "notes": "French-only catalog listing; individual program page was not canonicalized in this discovery pass."}, {"id": "usj-flsh-master-information-communication", "faculty": "Faculté des lettres et des sciences humaines Ramez G. Chagoury", "department": null, "major_category": "Arts, lettres et sciences humaines", "major": "Information et communication", "degree_type": "MASTER", "official_degree_name": "Master en information et communication", "thesis_or_non_thesis": null, "credits": null, "duration_value": null, "duration_unit": null, "duration_raw_text": null, "language": null, "delivery_mode": null, "program_description": null, "admission_requirements": null, "gre_requirement": null, "gmat_requirement": null, "english_requirement": null, "interview_requirement": null, "experience_requirement": null, "accreditation": null, "official_program_url": "https://usj.edu.lb/fr/e-doors/masters", "source_ids": ["usj_grad_catalog_fr", "usj_school_flsh"], "notes": "French-only catalog listing."}, {"id": "usj-flsh-master-lettres-francaises", "faculty": "Faculté des lettres et des sciences