requirement": null, "interview_requirement": null, "experience_requirement": null, "accreditation": null, "official_program_url": "https://usj.edu.lb/fr/fs/formations", "source_ids": ["usj_school_fs", "usj_fs_formations_fr"], "notes": "Doctoral page surfaced on the Faculty of Sciences graduate page."}, {"id": "usj-fs-phd-physique", "faculty": "Faculté des sciences", "department": "Département de physique", "major_category": "Ingénierie et technologie, sciences", "major": "Physique", "degree_type": "PHD", "official_degree_name": "Doctorat en physique", "thesis_or_non_thesis": null, "credits": null, "duration_value": null, "duration_unit": null, "duration_raw_text": null, "language": null, "delivery_mode": null, "program_description": null, "admission_requirements": null, "gre_requirement": null, "gmat_requirement": null, "english_requirement": null, "interview_requirement": null, "experience_requirement": null, "accreditation": null, "official_program_url": "https://usj.edu.lb/fr/fs/formations", "source_ids": ["usj_school_fs", "usj_fs_formations_fr"], "notes": "Doctoral page surfaced on the Faculty of Sciences graduate page."}, {"id": "usj-fs-phd-chimie", "faculty": "Faculté des sciences", "department": "Département de chimie", "major_category": "Ingénierie et technologie, sciences", "major": "Chimie", "degree_type": "PHD", "official_degree_name": "Doctorat en chimie", "thesis_or_non_thesis": null, "credits": null, "duration_value": null, "duration_unit": null, "duration_raw_text": null, "language": null, "delivery_mode": null, "program_description": null, "admission_requirements": null, "gre_requirement": null, "gmat_requirement": null, "english_requirement": null, "interview_requirement": null, "experience_requirement": null, "accreditation": null, "official_program_url": "https://usj.edu.lb/fr/fs/formations", "source_ids": ["usj_school_fs", "usj_fs_formations_fr"], "notes": "Doctoral page surfaced on the Faculty of Sciences graduate page."}, {"id": "usj-fs-phd-sciences-de-la-vie", "faculty": "Faculté des sciences", "department": "Département de sciences de la vie et de la terre", "major_category": "Ingénierie et technologie, sciences", "major": "Sciences de la vie", "degree_type": "PHD", "official_degree_name": "Doctorat en sciences de la vie", "thesis_or_non_thesis": null, "credits": null, "duration_value": null, "duration_unit": null, "duration_raw_text": null, "language": null, "delivery_mode": null, "program_description": null, "admission_requirements": null, "gre_requirement": null, "gmat_requirement": null, "english_requirement": null, "interview_requirement": null, "experience_requirement": null, "accreditation": null, "official_program_url": "https://usj.edu.lb/fr/fs/formations", "source_ids": ["usj_school_fs", "usj_fs_formations_fr"], "notes": "Doctoral page surfaced on the Faculty of Sciences graduate page."}]$USJ$::jsonb) AS seed(
        id TEXT,
        faculty TEXT,
        department TEXT,
        major_category TEXT,
        major TEXT,
        degree_type TEXT,
        official_degree_name TEXT,
        thesis_or_non_thesis TEXT,
        credits INTEGER,
        duration_value NUMERIC(10, 2),
        duration_unit TEXT,
        duration_raw_text TEXT,
        language TEXT,
        delivery_mode TEXT,
        program_description TEXT,
        admission_requirements TEXT,
        gre_requirement TEXT,
        gmat_requirement TEXT,
        english_requirement TEXT,
        interview_requirement TEXT,
        experience_requirement TEXT,
        accreditation TEXT,
        official_program_url TEXT,
        source_ids JSONB,
        notes TEXT
    );

    INSERT INTO graduate_program (
        university_id, faculty_id, department_id, degree_type_id, program_key,
        major_category, major, official_degree_name, thesis_or_non_thesis,
        credits, duration_value, duration_unit, primary_language_id, delivery_mode,
        program_description, official_program_url, source_id, notes
    )
    SELECT
        v_university_id,
        fac.id,
        dep.id,
        dt.id,
        seed.id,
        seed.major_category,
        seed.major,
        seed.official_degree_name,
        seed.thesis_or_non_thesis,
        seed.credits,
        seed.duration_value,
        seed.duration_unit,
        lang.id,
        seed.delivery_mode,
        seed.program_description,
        seed.official_program_url,
        (SELECT s.id
         FROM jsonb_array_elements_text(COALESCE(seed.source_ids, '[]'::jsonb)) WITH ORDINALITY AS src(source_seed_id, ord)
         JOIN usj_source_seed ss ON ss.source_id = src.source_seed_id
         JOIN source s ON s.university_id = v_university_id AND s.url = ss.url
         ORDER BY src.ord LIMIT 1),
        concat_ws(' ', NULLIF(seed.notes, ''), CASE WHEN seed.duration_raw_text IS NOT NULL THEN 'Original duration text: ' || seed.duration_raw_text END)
    FROM usj_program_seed seed
    JOIN university_faculty fac
      ON fac.university_id = v_university_id
     AND fac.name = seed.faculty
    LEFT JOIN university_department dep
      ON dep.university_id = v_university_id
     AND dep.faculty_id = fac.id
     AND dep.name = seed.department
    LEFT JOIN degree_type dt
      ON dt.code = seed.degree_type
    LEFT JOIN language lang
      ON LOWER(lang.name) = LOWER(seed.language)
    ON CONFLICT (university_id, program_key) DO UPDATE SET
        faculty_id = EXCLUDED.faculty_id,
        department_id = EXCLUDED.department_id,
        degree_type_id = EXCLUDED.degree_type_id,
        major_category = EXCLUDED.major_category,
        major = EXCLUDED.major,
        official_degree_name = EXCLUDED.official_degree_name,
        thesis_or_non_thesis = EXCLUDED.thesis_or_non_thesis,
        credits = EXCLUDED.credits,
        duration_value = EXCLUDED.duration_value,
        duration_unit = EXCLUDED.duration_unit,
        primary_language_id = EXCLUDED.primary_language_id,
        delivery_mode = EXCLUDED.delivery_mode,
        program_description = EXCLUDED.program_description,
        official_program_url = EXCLUDED.official_program_url,
        source_id = EXCLUDED.source_id,
        notes = EXCLUDED.notes,
        updated_at = NOW();

    INSERT INTO graduate_program_source (
        university_id, program_id, source_id, source_role, source_order, evidence_text, notes
    )
    SELECT
        v_university_id,
        gp.id,
        s.id,
        CASE WHEN src.ord = 1 THEN 'PRIMARY' ELSE 'SECONDARY' END,
        src.ord,
        ss.page_title,
        'Imported from USJ program sources.'
    FROM usj_program_seed seed
    JOIN graduate_program gp
      ON gp.university_id = v_university_id
     AND gp.program_key = seed.id
    JOIN LATERAL jsonb_array_elements_text(COALESCE(seed.source_ids, '[]'::jsonb)) WITH ORDINALITY AS src(source_seed_id, ord)
      ON TRUE
    JOIN usj_source_seed ss ON ss.source_id = src.source_seed_id
    JOIN source s ON s.university_id = v_university_id AND s.url = ss.url
    ON CONFLICT (program_id, source_id, source_role) DO UPDATE SET
        source_order = EXCLUDED.source_order,
        evidence_text = EXCLUDED.evidence_text,
        notes = EXCLUDED.notes,
        updated_at = NOW();

    INSERT INTO graduate_admission_requirement (
        university_id, faculty_id, department_id, program_id, scope_level, record_key,
        requirement_type, requirement_text, comparison_operator, threshold_value, threshold_unit, is_required, notes, source_id
    )
    SELECT * FROM (
        SELECT
            v_university_id, gp.faculty_id, gp.department_id, gp.id, 'PROGRAM'::TEXT, seed.id || ':admission_requirements',
            'GENERAL'::TEXT, seed.admission_requirements, NULL::TEXT, NULL::NUMERIC, NULL::TEXT, TRUE, NULL::TEXT, gp.source_id
        FROM usj_program_seed seed
        JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.id
        WHERE seed.admission_requirements IS NOT NULL
        UNION ALL
        SELECT
            v_university_id, gp.faculty_id, gp.department_id, gp.id, 'PROGRAM', seed.id || ':interview_requirement',
            'INTERVIEW'::TEXT, seed.interview_requirement, NULL::TEXT, NULL::NUMERIC, NULL::TEXT, TRUE, NULL::TEXT, gp.source_id
        FROM usj_program_seed seed
        JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.id
        WHERE seed.interview_requirement IS NOT NULL
    ) req
    ON CONFLICT (university_id, record_key) DO UPDATE SET
        faculty_id = EXCLUDED.faculty_id,
        department_id = EXCLUDED.department_id,
        program_id = EXCLUDED.program_id,
        scope_level = EXCLUDED.scope_level,
        requirement_type = EXCLUDED.requirement_type,
        requirement_text = EXCLUDED.requirement_text,
        is_required = EXCLUDED.is_required,
        source_id = EXCLUDED.source_id,
        updated_at = NOW();

    INSERT INTO graduate_accreditation (
        university_id, faculty_id, department_id, program_id, scope_level, record_key,
        name, authority, status, valid_from, valid_until, notes, source_id
    )
    SELECT
        v_university_id, NULL, NULL, NULL, 'UNIVERSITY', 'usj:university:accreditation',
        'Institutional accreditation',
        'ACQUIN',
        'Reaccredited',
        NULL,
        NULL,
        'USJ states that it received institutional reaccreditation in September 2025 for eight years from ACQUIN. The quality page says the accreditation is institutional and covers the university as a whole. Validity: 8 years.',
        s.id
    FROM source s
    WHERE s.university_id = v_university_id
      AND s.url = 'https://usj.edu.lb/qualite/acc-inst.php'
    ON CONFLICT (university_id, record_key) DO UPDATE SET
        notes = EXCLUDED.notes,
        source_id = EXCLUDED.source_id,
        updated_at = NOW();


