y": "USD", "billing_basis": "PER_CREDIT", "amount": 115, "category": "FS", "notes": "Official USJ 2024-2025 second-cycle tuition schedule."}, {"program_key": "usj-fmd-master-nutrition", "academic_year": "2024-2025", "currency": "USD", "billing_basis": "PER_CREDIT", "amount": 204, "category": "FMD", "notes": "Official USJ 2024-2025 second-cycle tuition schedule."}, {"program_key": "usj-fmd-master-physiotherapie", "academic_year": "2024-2025", "currency": "USD", "billing_basis": "PER_CREDIT", "amount": 204, "category": "FMD", "notes": "Official USJ 2024-2025 second-cycle tuition schedule."}, {"program_key": "usj-fmd-master-sante-publique", "academic_year": "2024-2025", "currency": "USD", "billing_basis": "PER_CREDIT", "amount": 107, "category": "ISSP", "notes": "Official USJ 2024-2025 second-cycle tuition schedule."}, {"program_key": "usj-fsi-master-sciences-infirmieres", "academic_year": "2024-2025", "currency": "USD", "billing_basis": "PER_CREDIT", "amount": 107, "category": "FSI", "notes": "Official USJ 2024-2025 second-cycle tuition schedule."}, {"program_key": "usj-fp-master-sciences-pharmaceutiques-biologiques", "academic_year": "2024-2025", "currency": "USD", "billing_basis": "PER_CREDIT", "amount": 71, "category": "FP", "notes": "Official USJ 2024-2025 second-cycle tuition schedule."}]$USJ$::jsonb) AS seed(
        program_key TEXT,
        academic_year TEXT,
        currency TEXT,
        billing_basis TEXT,
        amount NUMERIC(12, 2),
        category TEXT,
        notes TEXT
    )
    JOIN graduate_program gp
      ON gp.university_id = v_university_id
